sql.where:
l.customerid = #{customerId}
AND l.deletedat IS NULL
AND l.deviceid = #{deviceId}
AND d.number ILIKE '%' || #{deviceNumber} || '%'
AND l.ownername ILIKE '%' || #{ownerName} || '%'
AND l.assetstatus = #{assetStatus}
AND l.devicecondition = #{deviceCondition}
AND l.batterycondition = #{batteryCondition}
AND l.createdat >= #{dateFrom}
AND l.createdat <= #{dateTo}

mapper.select:
SELECT l.*, d.number AS devicenumber, u.name AS loggedbyusername FROM plugin_itam_log l LEFT JOIN devices d ON d.id = l.deviceid LEFT JOIN users u ON u.id = l.loggedbyuserid
ORDER BY l.createdat DESC
LIMIT #{pageSize} OFFSET (#{pageNum} - 1) * #{pageSize}

mapper.update:
UPDATE plugin_itam_log
SET deletedat = NOW(), deletedbyuserid = #{userId}
WHERE id = CAST(#{id} AS UUID) AND customerid = #{customerId} AND deletedat IS NULL
